import{_ as e,c as t,o as n,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Часто задаваемые вопросы: Решение проблем | opencode-plannotator","description":"Изучите методы решения распространённых проблем с Plannotator. Овладейте навыками быстрой диагностики таких проблем, как занятость портов, неоткрытый браузер, неудачная интеграция и др.","frontmatter":{"title":"Часто задаваемые вопросы: Решение проблем | opencode-plannotator","sidebarTitle":"Что делать при возникновении проблем","subtitle":"Часто задаваемые вопросы: Решение проблем","description":"Изучите методы решения распространённых проблем с Plannotator. Овладейте навыками быстрой диагностики таких проблем, как занятость портов, неоткрытый браузер, неудачная интеграция и др.","order":4},"headers":[],"relativePath":"ru/backnotprop/plannotator/faq/index.md","filePath":"ru/backnotprop/plannotator/faq/index.md"}'),l={name:"ru/backnotprop/plannotator/faq/index.md"};function i(r,a,s,p,d,c){return n(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h1><p>Эта глава поможет вам решить различные проблемы, возникающие при использовании Plannotator. Занятость портов, неоткрытый браузер или неудачная интеграция — для каждой проблемы есть соответствующее решение и методы отладки.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><div class="grid-cards"><a href="./common-problems/" class="card"><h3>🔧 Частые проблемы</h3><p>Решение распространённых проблем при использовании: занятость портов, неоткрытый браузер, отсутствие отображения планов, ошибки Git, неудачная загрузка изображений, проблемы интеграции с Obsidian/Bear и др.</p></a><a href="./troubleshooting/" class="card"><h3>🔍 Устранение неисправностей</h3><p>Освойте базовые методы устранения неисправностей: просмотр журналов, обработка ошибок и методы отладки. Научитесь быстро находить источник проблемы по выводу журналов.</p></a></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Частые проблемы → Устранение неисправностей</span></span>
<span class="line"><span>      ↓              ↓</span></span>
<span class="line"><span> Быстрое решение   Глубокая отладка</span></span></code></pre></div><p><strong>Рекомендуемый порядок</strong>:</p><ol><li><strong>Сначала ознакомьтесь с частыми проблемами</strong>: для большинства проблем здесь можно найти готовые решения</li><li><strong>Затем изучите устранение неисправностей</strong>: если частые проблемы не охватывают вашу ситуацию, научитесь самостоятельно диагностировать с помощью журналов и методов отладки</li></ol><div class="tip custom-block"><p class="custom-block-title">Рекомендации при возникновении проблем</p><p>Сначала поискайте по ключевым словам в разделе «Частые проблемы» (например, «порт», «браузер», «Obsidian»), чтобы найти соответствующее решение. Если проблема сложная или отсутствует в списке, обратитесь к разделу «Устранение неисправностей», чтобы изучить методы отладки.</p></div><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><p>Перед изучением этой главы рекомендуется выполнить:</p><ul><li>✅ <a href="./../start/getting-started/">Быстрый старт</a> — ознакомьтесь с основными концепциями Plannotator</li><li>✅ Установите плагин Claude Code или OpenCode (выберите один): <ul><li><a href="./../start/installation-claude-code/">Установка плагина Claude Code</a></li><li><a href="./../start/installation-opencode/">Установка плагина OpenCode</a></li></ul></li></ul><h2 id="дальнеишие-шаги" tabindex="-1">Дальнейшие шаги <a class="header-anchor" href="#дальнеишие-шаги" aria-label="Permalink to &quot;Дальнейшие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете продолжить изучение:</p><ul><li><a href="./../appendix/api-reference/">Справочник по API</a> — ознакомьтесь со всеми конечными точками API и форматами запросов/ответов</li><li><a href="./../appendix/data-models/">Модели данных</a> — ознакомьтесь со структурами данных, используемыми в Plannotator</li><li><a href="./../advanced/environment-variables/">Конфигурация переменных окружения</a> — ознакомьтесь подробно со всеми доступными переменными окружения</li></ul>`,15)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
